<style scoped>
.footer-body {
    position: absolute;
    height: 65px;
    width: 305px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    z-index: 0;
    inset: 0;
    margin: auto auto 25px auto;
    padding: 0 20px;
    box-sizing: border-box;
}

.plate {
    position: absolute;
    width: 305px;
    height: 55px;
    background-image: url('../assets/img/plate.svg');
    backdrop-filter: blur(6px);
    border-radius: 75px;
    box-shadow: 0 4px 4px 0 rgb(0, 0, 0, .25);
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
    z-index: -1;
    inset: 0;
    margin: auto;
}

.create-room-button {
    width: 30px;
    height: 30px;
}

.settings-button {
    width: 30px;
    height: 30px;
}

.switch-container {
    width: 155px;
    height: 65px;
}

.mode-switch {
    
    display: inline-block;
    position: relative;
    width: 155px;
    height: 65px;

}


.mode-switch .mode-switch-input {
    height: 0;
    width: 0;
    opacity: 0;
    display: block;
}


.mode-switch .mode-switch-slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    bottom: 0;
    left: 0;
    right: 0;
    border-radius: 31px;
    border: 1px #4FC0FF solid;
    background: #212935;
    transition: 0.4s;
}


.mode-switch .mode-switch-slider::before {

    content: "";
    position: absolute;
    cursor: pointer;
    bottom: -1px;
    left: -1.2px;
    height: 65px;
    width: 65px;
    border-radius: 50%;
    background-color: #FFFF97;
    transition: 0.4s;

}


.mode-switch .mode-drivers-rooms {
    position: absolute;
    width: 40px;
    height: 40px;
    transition: 0.6s;
    box-sizing: border-box;
    inset: 0;
    margin: auto auto auto 11.75px;
}


.mode-switch .mode-passangers-rooms {
    position: absolute;
    width: 45px;
    height: 32px;
    transition: 0.6s;
    inset: 0;
    margin: auto 10px auto auto;
}

.mode-switch-input:checked ~ .mode-passangers-rooms {
    fill: #0D3E5D;
}


.mode-switch-input:checked ~ .mode-drivers-rooms {
    fill: #4FC0FF;
}


.mode-switch-input:checked + .mode-switch-slider::before {

    transform: translateX(90.5px);

}
</style>
